static bool chk_bit (const BitArrayCL* ba, u16 idx) {
    if (ba == nullptr) {
        return false;
    }
    if (idx >= ba->get_count()) {
        return false;
    }
    return ba->get_bit(idx) == 1;
}

bool GeneralAssessor::chk (const ItemReqsStruct& reqs, const AssessorCtx& ctx) {
    for (u32 j = 0; j < MAX_PREREQ_COUNT; ++j) {
        const u8 tp = reqs.types[j];
        if (tp == ITEM_REQ_TYPE_NONE) {
            break;
        }
        const u16 ix = reqs.indices[j];
        if (ix == U16_KEY_NULL) {
            return false;
        }
        switch (tp) {
            case ITEM_REQ_TYPE_TECH:
                if (!chk_bit(ctx.m_tech, ix)) {
                    return false;
                }
                break;
            case ITEM_REQ_TYPE_RESOURCE:
                if (!chk_bit(ctx.m_resource, ix)) {
                    return false;
                }
                break;
            case ITEM_REQ_TYPE_BUILDING:
                if (!chk_bit(ctx.m_building, ix)) {
                    return false;
                }
                break;
            case ITEM_REQ_TYPE_FLAG:
                if (!chk_bit(ctx.m_city_flag, ix)) {
                    return false;
                }
                break;
            case ITEM_REQ_TYPE_CIV:
                if (!chk_bit(ctx.m_civ, ix)) {
                    return false;
                }
                break;
            default:
                return false;
        }
    }
    return true;
}

BitArrayCL* GeneralAssessor::assess_building (u16 item_count, const BuildingStaticDataStruct* items, const AssessorCtx& ctx) {
    BitArrayCL* result = new BitArrayCL(item_count);
    if (items == nullptr) {
        return result;
    }
    for (u16 i = 0; i < item_count; ++i) {
        if (chk(items[i].reqs, ctx)) {
            result->set_bit(i);
        }
    }
    return result;
}

